const MenuPage = () => {
  const [foods, setFoods] = useState([]);
  const [filteredFoods, setFilteredFoods] = useState([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('all');
  const [loading, setLoading] = useState(true);
  const { addItem, updateItemQuantity, getItemQuantity } = useCart();

  // Function to get image path based on food name
  const getFoodImage = (foodName) => {
    const name = foodName.toLowerCase();

    // Create a consistent index based on food name
    const foodNames = [
      'classic burger', 'bbq burger', 'cheese burger', 'veggie burger', 'chicken wings', 'fish tacos',
      'margherita pizza', 'pepperoni pizza', 'hawaiian pizza', 'vegetarian pizza',
      'spaghetti carbonara', 'fettuccine alfredo', 'lasagna',
      'greek salad', 'caesar salad',
      'french fries', 'onion rings', 'garlic bread', 'mushroom soup', 'spring rolls',
      'coca cola', 'orange juice', 'lemonade', 'chocolate milkshake',
      'chocolate cake', 'tiramisu', 'apple pie', 'brownies', 'ice cream',
      'sushi'
    ];

    const availableImages = [
      '/images/foods/burger.jpg',
      '/images/foods/BBQ_burger.jpg',
      '/images/foods/cheese-burger.jpg',
      '/images/foods/chicken.jpg',
      '/images/foods/pizza-margherita.jpg',
      '/images/foods/Pepperoni_pizza.jpg',
      '/images/foods/pizza.jpg',
      '/images/foods/Spaghetti_Carbonara.jpg',
      '/images/foods/pasta.jpg',
      '/images/foods/lasagna.jpg',
      '/images/foods/salad.jpg',
      '/images/foods/french-fries.jpg',
      '/images/foods/onion-rings.jpg',
      '/images/foods/mozzarella-stick.jpg',
      '/images/foods/coca-cola.jpg',
      '/images/foods/orange_juice.jpg',
      '/images/foods/drinks.jpg',
      '/images/foods/dessert.jpg',
      '/images/foods/brownies.jpg',
      '/images/foods/ice_cream.jpg',
      '/images/foods/sushi.jpg'
    ];

    // Find exact match first
    const exactMatchIndex = foodNames.findIndex(food => name.includes(food));
    if (exactMatchIndex !== -1 && exactMatchIndex < availableImages.length) {
      return availableImages[exactMatchIndex];
    }

    // Fallback: use hash to get unique image
    const hashIndex = name.split('').reduce((acc, char) => acc + char.charCodeAt(0), 0);
    return availableImages[Math.abs(hashIndex) % availableImages.length];
  };

  const categories = [
    { value: 'all', label: 'All Categories' },
    { value: 'Burgers', label: 'Burgers' },
    { value: 'Pizza', label: 'Pizza' },
    { value: 'Pasta', label: 'Pasta' },
    { value: 'Desserts', label: 'Desserts' },
    { value: 'Drinks', label: 'Drinks' },
    { value: 'Salads', label: 'Salads' }
  ];

  useEffect(() => {
    const loadFoods = async () => {
      try {
        setLoading(true);
        const response = await foodAPI.getAll();

        if (response.success) {
          console.log('Menu API Response:', response);
          const foodItems = response.data?.food_items || response.data || [];
          console.log('Menu food items:', foodItems);
          setFoods(foodItems);
          setFilteredFoods(foodItems);
        } else {
          console.error('Failed to load foods:', response.message);
          setFoods([]);
          setFilteredFoods([]);
        }
      } catch (error) {
        console.error('Error loading foods:', error);
        setFoods([]);
        setFilteredFoods([]);
      } finally {
        setLoading(false);
      }
    };

    loadFoods();
  }, []);

  useEffect(() => {
    let filtered = foods;

    if (searchTerm) {
      filtered = filtered.filter(food =>
        food.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
        food.description.toLowerCase().includes(searchTerm.toLowerCase())
      );
    }

    if (selectedCategory !== 'all') {
      filtered = filtered.filter(food => food.category_name === selectedCategory);
    }

    setFilteredFoods(filtered);
  }, [searchTerm, selectedCategory, foods]);

  const handleAddToCart = (food) => {
    addItem({
      food_id: food.id,
      name: food.name,
      price: parseFloat(food.price),
      quantity: 1
    });
  };

  const handleQuantityChange = (foodId, change) => {
    const currentQuantity = getItemQuantity(foodId);
    const newQuantity = currentQuantity + change;

    if (newQuantity > 0) {
      updateItemQuantity(foodId, newQuantity);
    }
  };

  if (loading) {
    return (
      <MenuContainer>
        <LoadingSpinner />
      </MenuContainer>
    );
  }

  return (
    <MenuContainer>
      <MenuHeader>
        <MenuTitle>Our Menu</MenuTitle>
        <MenuSubtitle>Delicious food made with fresh ingredients</MenuSubtitle>
      </MenuHeader>

      <SearchFilterSection>
        <SearchContainer>
          <Input
            type="text"
            placeholder="Search for food..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            icon={<Search size={20} />}
          />
        </SearchContainer>

        <FilterContainer>
          <Filter size={20} />
          <CategoryFilter
            value={selectedCategory}
            onChange={(e) => setSelectedCategory(e.target.value)}
          >
            {categories.map(category => (
              <option key={category.value} value={category.value}>
                {category.label}
              </option>
            ))}
          </CategoryFilter>
        </FilterContainer>
      </SearchFilterSection>

      {filteredFoods.length === 0 ? (
        <EmptyMessage>
          No food items found matching your criteria.
        </EmptyMessage>
      ) : (
        <MenuGrid>
          {filteredFoods.map(food => {
            const quantity = getItemQuantity(food.id);
            return (
              <FoodCard key={food.id}>
                <CardBody>
                  <FoodImage>
                    <img 
                      src={getFoodImage(food.name)} 
                      alt={food.name}
                      onError={(e) => {
                        e.target.style.display = 'none';
                        e.target.nextSibling.style.display = 'flex';
                      }}
                    />
                    <div style={{ 
                      display: 'none', 
                      alignItems: 'center', 
                      justifyContent: 'center',
                      height: '100%',
                      color: theme.colors.gray[400]
                    }}>
                      <Plus size={48} />
                    </div>
                    {food.popular && <PopularBadge>Popular</PopularBadge>}
                  </FoodImage>

                  <FoodContent>
                    <FoodHeader>
                      <FoodName>{food.name}</FoodName>
                      <FoodCategory>{food.category_name}</FoodCategory>
                    </FoodHeader>

                    <FoodDescription>{food.description}</FoodDescription>

                    <FoodMeta>
                      <Rating>
                        <Star size={16} fill="currentColor" />
                        <span>{food.rating || 4.0}</span>
                      </Rating>
                      <PrepTime>
                        <Clock size={16} />
                        <span>{food.prepTime || '15-20 min'}</span>
                      </PrepTime>
                    </FoodMeta>

                    <FoodFooter>
                      <FoodPrice>${parseFloat(food.price).toFixed(2)}</FoodPrice>
                      <QuantityControls>
                        {quantity > 0 ? (
                          <>
                            <QuantityButton onClick={() => handleQuantityChange(food.id, -1)}>
                              <Minus size={16} />
                            </QuantityButton>
                            <QuantityDisplay>{quantity}</QuantityDisplay>
                            <QuantityButton onClick={() => handleQuantityChange(food.id, 1)}>
                              <Plus size={16} />
                            </QuantityButton>
                          </>
                        ) : (
                          <QuantityButton 
                            variant="primary" 
                            onClick={() => handleAddToCart(food)}
                          >
                            <ShoppingCart size={16} />
                          </QuantityButton>
                        )}
                      </QuantityControls>
                    </FoodFooter>
                  </FoodContent>
                </CardBody>
              </FoodCard>
            );
          })}
        </MenuGrid>
      )}
    </MenuContainer>
  );
};

export default MenuPage;
